import { describe, it, expect } from 'vitest';
import { calculatePremium } from './premium.js';

describe('calculatePremium - base premiums', () => {
  it('empty item list yields only the processing fee', () => {
    expect(calculatePremium({ yearsWithMHPCO: 5, contractIndex: 1 }, [])).toBe(5);
  });

  it('plain sword for long-standing returning customer', () => {
    // base 100, loyalty 20% off => 80, follow-up 15% off => 65, fee 5 => 70
    expect(calculatePremium({ yearsWithMHPCO: 3, contractIndex: 1 }, [
      { type: 'sword', material: 'steel', enchantment: 3, cursed: false }
    ])).toBe(70);
  });

  it('plain amulet base premium for first contract newcomer', () => {
    // base 60 + 10% first insurance = 66 + 5 fee = 71
    expect(calculatePremium({ yearsWithMHPCO: 0, contractIndex: 0 }, [
      { type: 'amulet', material: 'silver', enchantment: 2, cursed: false }
    ])).toBe(71);
  });
});

describe('calculatePremium - integration examples from prompt', () => {
  it('newcomer with cursed sword => 165', () => {
    expect(calculatePremium({ yearsWithMHPCO: 0, contractIndex: 0 }, [
      { type: 'sword', material: 'steel', enchantment: 3, cursed: true }
    ])).toBe(165);
  });

  it('long-standing customer second contract with cursed high-enchant sword => 160', () => {
    expect(calculatePremium({ yearsWithMHPCO: 3, contractIndex: 1 }, [
      { type: 'sword', material: 'steel', enchantment: 7, cursed: true }
    ])).toBe(160);
  });
});

describe('calculatePremium - components and blocks', () => {
  it('2 runes => 50 base, +fee 5 for newcomer first contract => 50 + 5G first ins => 50*1.1 = 55 + 5 = 60', () => {
    // 2 runes base = 50. First insurance: 50*1.1 = 55. +5 fee = 60
    expect(calculatePremium({ yearsWithMHPCO: 0, contractIndex: 0 }, [
      { type: 'rune' },
      { type: 'rune' }
    ])).toBe(60);
  });

  it('3 runes => 60 base premium (block applies)', () => {
    // base 60. first insurance: 60*1.1 = 66 + 5 = 71
    expect(calculatePremium({ yearsWithMHPCO: 0, contractIndex: 0 }, [
      { type: 'rune' },
      { type: 'rune' },
      { type: 'rune' }
    ])).toBe(71);
  });

  it('4 runes => 100 base premium (no block)', () => {
    // base 100, first ins 110 + 5 = 115
    expect(calculatePremium({ yearsWithMHPCO: 0, contractIndex: 0 }, [
      { type: 'rune' }, { type: 'rune' }, { type: 'rune' }, { type: 'rune' }
    ])).toBe(115);
  });

  it('7 runes => 175 base (60 + 25*4 = 160? No: 7 runes = 3 + 4 individual = 60 + 4*25 = 160). Actually prompt says 175', () => {
    // Per prompt: 7 runes -> 175. So: only one block of 3? 60 + 4*25 = 160. Or 6 blocks impossible.
    // Actually maybe 7 = 3+3+1 blocks of 3 each: 60+60+25 = 145. Hmm.
    // Re-reading: prompt says "7 runes → 175 G base premium". Let me reconsider.
    // 60 (3 block) + 4*25 = 60+100=160? But prompt says 175.
    // Maybe blocks only apply once - exactly 3 alike => block; 4+ => no block at all. So 7 = 7*25 = 175. Yes!
    // "the block requires exactly 3" - so 7 runes have no block at all: 7*25 = 175
    expect(calculatePremium({ yearsWithMHPCO: 0, contractIndex: 0 }, [
      { type: 'rune' }, { type: 'rune' }, { type: 'rune' }, { type: 'rune' },
      { type: 'rune' }, { type: 'rune' }, { type: 'rune' }
    ])).toBe(Math.ceil(175 * 1.1) + 5); // 192.5 -> 193 + 5 = 198
  });

  it('2 runes + 1 moonstone => 75 base premium', () => {
    // 2*25 + 25 = 75 (no block: different types). first ins 82.5 -> 83 + 5 = 88
    expect(calculatePremium({ yearsWithMHPCO: 0, contractIndex: 0 }, [
      { type: 'rune' }, { type: 'rune' }, { type: 'moonstone' }
    ])).toBe(88);
  });

  it('3 runes + 3 moonstones => 120 base premium', () => {
    // 60 + 60 = 120. first ins 132 + 5 = 137
    expect(calculatePremium({ yearsWithMHPCO: 0, contractIndex: 0 }, [
      { type: 'rune' }, { type: 'rune' }, { type: 'rune' },
      { type: 'moonstone' }, { type: 'moonstone' }, { type: 'moonstone' }
    ])).toBe(137);
  });
});

describe('calculatePremium - modifier scope', () => {
  it('cursed sword + plain amulet => policy base 160 + 50 curse', () => {
    // cursed sword base 100, plain amulet 60. Sum 160. Curse +50 (50% of cursed sword's base) = 210
    // newcomer first contract: first ins 210*1.1 = 231. +5 = 236
    expect(calculatePremium({ yearsWithMHPCO: 0, contractIndex: 0 }, [
      { type: 'sword', material: 'steel', enchantment: 3, cursed: true },
      { type: 'amulet', material: 'silver', enchantment: 2, cursed: false }
    ])).toBe(236);
  });
});

describe('calculatePremium - rounding', () => {
  it('rounds up in MHPCO favor', () => {
    // Construct a case where calculation yields fractional - 197.5 => 198
    // For example: amulet base 60, +10% first insurance = 66, then... easier: design custom.
    // base 100 sword cursed +50 = 150, first ins 165, + 5 = 170 (clean)
    // Try amulet (60) high-enchant +30% of 60 = 18 => 78, fee 5 = 83 (clean)
    // sword (100) high-enchant 30 = 130, loyalty 20% = 104, follow-up 15% = 88.4 + 5 = 93.4 => 94
    expect(calculatePremium({ yearsWithMHPCO: 3, contractIndex: 1 }, [
      { type: 'sword', material: 'steel', enchantment: 5, cursed: false }
    ])).toBe(94);
  });
});

